    public Object parseOrderStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "ACTIVE", "open" );
            put( "COMPLETED", "closed" );
            put( "CANCELED", "canceled" );
            put( "EXPIRED", "canceled" );
            put( "REJECTED", "canceled" );
        }};
        return this.safeString(statuses, ((String)status), status);
    }

    public Object parseOrder(Object order, Object... optionalArgs)
    {
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.parse8601(this.safeString(order, "child_order_date"));
        Object price = this.safeString(order, "price");
        Object amount = this.safeString(order, "size");
        Object filled = this.safeString(order, "executed_size");
        Object remaining = this.safeString(order, "outstanding_size");
        Object status = this.parseOrderStatus(this.safeString(order, "child_order_state"));
        Object type = this.safeStringLower(order, "child_order_type");
        Object side = this.safeStringLower(order, "side");
        Object marketId = this.safeString(order, "product_code");
        Object symbol = this.safeSymbol(marketId, market);
        Object fee = null;
        Object feeCost = this.safeNumber(order, "total_commission");
        if (Helpers.isTrue(!Helpers.isEqual(feeCost, null)))
        {
            final Object finalFeeCost = feeCost;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCost );
                put( "currency", null );
                put( "rate", null );
            }};
        }
        Object id = this.safeString(order, "child_order_acceptance_id");
        final Object finalFee = fee;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "clientOrderId", null );
            put( "info", order );
            put( "timestamp", timestamp );
            put( "datetime", BitflyerCore.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", null );
            put( "status", status );
            put( "symbol", symbol );
            put( "type", type );
            put( "timeInForce", null );
            put( "postOnly", null );
            put( "side", side );
            put( "price", price );
            put( "triggerPrice", null );
            put( "cost", null );
            put( "amount", amount );
            put( "filled", filled );
            put( "remaining", remaining );
            put( "fee", finalFee );
            put( "average", null );
            put( "trades", null );
        }}, market);
    }

    /**
     * @method
     * @name bitflyer#fetchOrders
     * @description fetches information on multiple orders made by the user
     * @see https://lightning.bitflyer.com/docs?lang=en#list-orders
     * @param {string} symbol unified market symbol of the market orders were made in
     * @param {int} [since] the earliest time in ms to fetch orders for
     * @param {int} [limit] the maximum number of order structures to retrieve
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {Order[]} a list of [order structures]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOrders(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, 100);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " fetchOrders() requires a symbol argument")) ;
            }
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "product_code", Helpers.GetValue(market, "id") );
                put( "count", limit );
            }};
            Object response = (this.privateGetGetchildorders(this.extend(request, parameters))).join();
            Object orders = this.parseOrders(response, market, since, limit);
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                orders = this.filterBy(orders, "symbol", symbol);
            }
            return orders;
        });

    }

